#!/usr/bin/env python3
import json, os, subprocess, sys

query = (sys.argv[1] if len(sys.argv) > 1 else "").strip().lower()

wf_data = os.getenv("alfred_workflow_data") or os.getcwd()
os.makedirs(wf_data, exist_ok=True)
conf = os.path.join(wf_data, "favorites.json")

# Load config (extras / overrides / excludes)
cfg = {"extras": [], "overrides": {}, "excludes": []}
try:
    with open(conf, "r", encoding="utf-8") as f:
        cfg.update(json.load(f))
except FileNotFoundError:
    pass

ghq = "/opt/homebrew/bin/ghq"
try:
    out = subprocess.check_output([ghq, "list", "--full-path"], text=True)
    repos = [l for l in out.strip().splitlines() if l]
except Exception:
    repos = []

ghq_root = ""
try:
    ghq_root = subprocess.check_output([ghq, "root"], text=True).strip()
except Exception:
    pass

excludes = cfg.get("excludes", [])
overrides = cfg.get("overrides", {})

items = []

for full_path in repos:
    rel = full_path.replace(ghq_root + "/", "", 1) if ghq_root else full_path
    # Remove host/owner prefix (e.g. github.com/yoshihiko555/) to get repo key
    parts = rel.split("/")
    repo_key = "/".join(parts[2:]) if len(parts) > 2 else rel

    if any(ex in repo_key for ex in excludes):
        continue

    if repo_key in overrides:
        name = overrides[repo_key].get("name", repo_key)
    else:
        name = repo_key

    if query and query not in f"{name} {repo_key} {full_path}".lower():
        continue

    items.append({"title": name, "subtitle": full_path, "arg": full_path})

# Append extras (non-ghq paths)
for ex in cfg.get("extras", []):
    name = ex.get("name", os.path.basename(ex.get("path", "")))
    path = ex.get("path", "")
    if query and query not in f"{name} {path}".lower():
        continue
    items.append({"title": name, "subtitle": path, "arg": path})

print(json.dumps({"items": items}, ensure_ascii=False))
